// claim-office.ts

type Customer = {
  yearsWithMHPCO: number;
};

type Item = {
  type: string;
  material?: string;
  cursed?: boolean;
  enchantment?: number;
};

type Damage = {
  itemType: string;
  amount: number;
};

type Incident = {
  cause: string;
  damages: Damage[];
};

type Step = {
  op: string;
  items?: Item[];
  policy?: number;
  incident?: Incident;
};

type ScenarioInput = {
  customer: Customer;
  steps: Step[];
};

type QuoteResult = {
  premium: number;
};

type ClaimResult = {
  payout: number;
  remainingCap: number;
};

type StepResult = QuoteResult | ClaimResult;

type ScenarioOutput = {
  results: StepResult[];
};

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const CURSE_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const LOYALTY_YEARS_THRESHOLD = 2;
const LOYALTY_DISCOUNT_RATE = 0.2;
const FOLLOW_UP_DISCOUNT_RATE = 0.15;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_BASE_PREMIUM = 60;

